section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "unit-testing-output",
  "required": [
    "naming_convention",
    "aaa_compliance",
    "avg_runtime_ms",
    "coverage_line",
    "coverage_branch",
    "forbidden_seen"
  ],
  "properties": {
    "naming_convention": {
      "description": "Chosen naming convention."
    },
    "aaa_compliance": {
      "description": "% of tests with visible AAA sections."
    },
    "avg_runtime_ms": {
      "description": "Mean test runtime; alert at >10ms."
    },
    "coverage_line": {
      "description": "Line coverage %."
    },
    "coverage_branch": {
      "description": "Branch coverage %."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
